distance = math.sqrt(dx ** 2 + dy ** 2)
MAX_PULL = 150 distance = min(distance, MAX_PULL)
self.angle = math.atan2(-dy, dx)
ratio = distance / MAX_PULL self.power = MIN_POWER + ratio * (MAX_POWER - MIN_POWER)
